import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';

const FormList = () => {
  const [forms, setForms] = useState([]);

  useEffect(() => {
    const fetchForms = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/forms');
        setForms(response.data);
      } catch (error) {
        console.error('Error fetching forms:', error);
      }
    };

    fetchForms();
  }, []);

  return (
    <div className="form-list">
      <div className="header">
        <h2>My Forms</h2>
        <Link to="/create" className="btn create-btn">
          Create New Form
        </Link>
      </div>

      <div className="forms-grid">
        {forms.map((form) => (
          <div key={form._id} className="form-card">
            <h3>{form.title}</h3>
            <p>{form.fields.length} fields</p>
            <p>{form.submissions?.length || 0} submissions</p>
            <Link to={`/form/${form._id}`} className="btn view-btn">
              View Form
            </Link>
          </div>
        ))}
      </div>

      {forms.length === 0 && (
        <div className="no-forms">
          <p>No forms created yet. Create your first form!</p>
        </div>
      )}
    </div>
  );
};

export default FormList;
